class MyHashSet:
    def __init__(self):
        self.size = 1009
        self.buckets = [[] for _ in range(self.size)]
    def add(self, key):
        b = self.buckets[key % self.size]
        if key not in b:
            b.append(key)
    def remove(self, key):
        b = self.buckets[key % self.size]
        if key in b:
            b.remove(key)
    def contains(self, key):
        return key in self.buckets[key % self.size]

