class MyHashSet {
    constructor() {
        this.size = 1009;
        this.buckets = Array.from({ length: this.size }, () => []);
    }
    add(key) {
        const b = this.buckets[key % this.size];
        if (b.indexOf(key) === -1) b.push(key);
    }
    remove(key) {
        const b = this.buckets[key % this.size];
        const i = b.indexOf(key);
        if (i !== -1) b.splice(i, 1);
    }
    contains(key) {
        return this.buckets[key % this.size].indexOf(key) !== -1;
    }
}
